const d = msg.payload || {};
const ts = Date.now();
const type = d.alertType || d.type || 'ALERT';
const text = d.alertMsg || d.message || d.msg || JSON.stringify(d);
const suppressUntil = global.get('alarmSuppressUntil') || 0;
const suppressed = Date.now() < suppressUntil && /alarm|tilt|door|buzzer|fire|smoke/i.test(type + ' ' + text);

const list = global.get('alertList') || [];
list.unshift({ id: ts, deviceId: d.deviceId || d.device_id || 'ESP32_BOX_001', type: type, text: text, ts: ts, suppressed: suppressed });
global.set('alertList', list.slice(0, 20));

const view = list.slice(0, 20).map(function (i) {
    return (i.suppressed ? '[抑制] ' : '') + '[' + new Date(i.ts).toLocaleString('zh-CN', { hour12: false }) + '] ' + i.type + ' - ' + i.text;
}).join('\n');

return [
    { payload: view },
    { topic: 'INSERT INTO alerts (device_id,ts,alert_type,alert_msg,is_ack) VALUES ($p1,$p2,$p3,$p4,$p5)', payload: [d.deviceId || d.device_id || 'ESP32_BOX_001', ts, type, text, suppressed ? 1 : 0] }
];

const d = msg.payload || {};
const ts = Date.now();
const action = d.action || d.cmd || d.command || 'ACK';
const status = d.status || ((d.success === false || d.ok === false) ? 'failed' : 'ack');
return [{ topic: 'INSERT INTO commands (device_id,ts,action,status,source,raw_json) VALUES ($p1,$p2,$p3,$p4,$p5,$p6)', payload: [d.deviceId || d.device_id || 'ESP32_BOX_001', ts, action, status, 'mqtt_ack', JSON.stringify(d)] }];

const d = global.get('latestTelemetry') || {};
const ts = d.lastSeen || 0;
const age = ts ? Date.now() - ts : null;
const online = age !== null && age < 15000;
const front = !!(d.frontLight || d.frontDoor);
const back = !!(d.backLight || d.backDoor);
const suppressed = (global.get('alarmSuppressUntil') || 0) > Date.now();

const status = [
  '设备: ' + (d.deviceId || 'ESP32_BOX_001'),
  '在线: ' + (online ? '是' : '否'),
  '最后上报: ' + (ts ? new Date(ts).toLocaleString('zh-CN', { hour12: false }) : '未知'),
  '离线时长: ' + (age === null ? '未知' : Math.floor(age / 1000) + ' 秒'),
  '风扇: ' + (d.fanStatus ? '开' : '关'),
  '前门: ' + (front ? '开' : '关'),
  '后门: ' + (back ? '开' : '关'),
  '告警抑制: ' + (suppressed ? '开启' : '关闭')
].join('\n');

return [{ payload: status }];

const d = global.get('latestTelemetry') || { deviceId: 'ESP32_BOX_001', temperature: 0, humidity: 0, capacity: 0, airQuality: 0, humanDetect: false, fanStatus: false, frontLight: false, backLight: false, frontDoor: false, backDoor: false, tiltAngle: 0, sensorFaults: [], buzzerMode: 'off', netMode: 'STA', systemState: 'OFFLINE', lastSeen: 0, mqttOnline: false, mqttBrokerOnline: true };
const age = d.lastSeen ? Date.now() - d.lastSeen : null;
const front = Boolean(d.frontLight ?? d.frontDoor ?? d.front_door ?? false);
const back = Boolean(d.backLight ?? d.backDoor ?? d.back_door ?? false);
msg.statusCode = 200;
msg.payload = { code: 200, msg: 'ok', data: { ...d, frontLight: front, frontDoor: front, backLight: back, backDoor: back, online: age !== null && age < 15000, lastTelemetryAgeMs: age, mqttBrokerOnline: true, systemState: d.systemState || (age !== null && age < 15000 ? 'STANDBY' : 'OFFLINE') } };
return msg;

let body = msg.payload;

if (typeof body === "string") {
  try {
    body = JSON.parse(body);
  } catch (e) {
    body = {};
  }
}

if (!body || typeof body !== "object") {
  body = {};
}

if (msg.req && msg.req.body && typeof msg.req.body === "object") {
  body = Object.assign({}, msg.req.body, body);
}

const latest = global.get("latestTelemetry") || {};
const age = latest.lastSeen ? Date.now() - latest.lastSeen : 1e12;

const action = String(body.action || body.command || body.cmd || "")
  .trim()
  .toUpperCase();

const deviceId =
  body.deviceId ||
  body.device_id ||
  latest.deviceId ||
  "ESP32_BOX_001";

if (body.adminToken && body.adminToken !== "admin_auth_secret01") {
  msg.statusCode = 401;
  msg.payload = {
    code: 401,
    msg: "管理员Token错误"
  };
  return [null, null, msg];
}

if (!action) {
  msg.statusCode = 400;
  msg.payload = {
    code: 400,
    msg: "缺少action",
    debugPayload: body
  };
  return [null, null, msg];
}

if (action === "ALARM_STOP") {
  global.set("alarmSuppressUntil", Date.now() + 300000);
}

const cmd = {
  deviceId,
  cmd: action,
  action,
  command: action,
  ts: Date.now()
};

msg.statusCode = 200;
msg.payload = {
  code: 200,
  msg: age > 15000 ? "ok_offline_warning" : "ok",
  data: {
    sent: true,
    topic: "device/clothes_box/control",
    command: cmd,
    offlineWarning: age > 15000
  }
};

return [
  {
    topic: "device/clothes_box/control",
    payload: JSON.stringify(cmd)
  },
  {
    topic: "INSERT INTO commands (device_id,ts,action,status,source,raw_json) VALUES ($p1,$p2,$p3,$p4,$p5,$p6)",
    payload: [
      deviceId,
      Date.now(),
      action,
      "sent",
      "html_frontend",
      JSON.stringify(body)
    ]
  },
  msg
];

let body = msg.payload || {};
if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch (e) { body = {}; }
}
if (body.adminToken && body.adminToken !== 'admin_auth_secret01') {
  msg.statusCode = 401;
  msg.payload = { code: 401, msg: '管理员Token错误' };
  return [null, msg];
}
const cfg = {
  deviceId: body.deviceId || 'ESP32_BOX_001',
  wifiSsid: body.wifiSsid || body.ssid || '',
  wifiPass: body.wifiPass || body.password || '',
  mqttServer: body.mqttServer || '192.168.34.228',
  mqttPort: Number(body.mqttPort || 1883),
  ts: Date.now()
};
msg.statusCode = 200;
msg.payload = { code: 200, msg: 'ok', data: { sent: true, topic: 'device/clothes_box/config', config: { ...cfg, wifiPass: cfg.wifiPass ? '******' : '' } } };
return [
  { topic: 'device/clothes_box/config', payload: JSON.stringify(cfg) },
  msg
];

const action = msg.payload;
const latest = global.get('latestTelemetry') || {};
const age = latest.lastSeen ? Date.now() - latest.lastSeen : 1e12;
const deviceId = latest.deviceId || 'ESP32_BOX_001';

if (action === 'ALARM_STOP') {
  global.set('alarmSuppressUntil', Date.now() + 300000);
}

const cmd = { deviceId: deviceId, cmd: action, action: action, ts: Date.now() };

return [
  { topic: 'device/clothes_box/control', payload: JSON.stringify(cmd) },
  { topic: 'INSERT INTO commands (device_id,ts,action,status,source,raw_json) VALUES ($p1,$p2,$p3,$p4,$p5,$p6)', payload: [deviceId, Date.now(), action, 'sent', 'dashboard', JSON.stringify({ action: action })] },
  { payload: '动作: ' + action + '\n设备: ' + deviceId + '\n时间: ' + new Date().toLocaleString('zh-CN', { hour12: false }) }
];
